	/***********************************************************************************************************
		Disable Hardlinkin
	***********************************************************************************************************/
	if(!is_array(@$object)) { @http_response_code(404); Header("Location: ../"); exit(); }
	
	/***********************************************************************************************************
		Validate API access using an API key.
		
		This function checks whether the current request is authorized
		based on the POSTed API credentials (a global api token).
		
		Behavior:
		- Uses $object["extension"] and $object["hive_mode_config"] to detect 
		  the current site and extension context.
		- Verifies if the given API token and related request data are valid.
		- Optionally checks if the api key has the required permissions.
		- Returns false if access is denied.
		- If the third parameter is set to true, script execution will stop 
		  automatically when access is denied; if false, you need to handle it yourself.

		Parameters:
		- $object: The current object context
		- array of global api permission names (or false to skip permission check)
		- boolean: 
			true  = stop execution automatically if access is denied
			false = just return false if access is denied
	***********************************************************************************************************/
	$access = hive__api_global_access($object, array($object["hive_mode_config"]["prefix_variables"]."admin"), true);
	
	/***********************************************************************************************************
		Ouput on successfull request.
	***********************************************************************************************************/
	echo hive__api_output_success($object, "Succesfull - This endpoint serves no purpose.", 200);